import React, { useState } from 'react';
import { View, Button, Alert } from 'react-native';
import { RNIap, purchaseUpdatedListener } from 'react-native-iap';
import DeviceInfo from 'react-native-device-info';

const itemSkus = ['com.example.product1', 'com.example.product2'];

const PaymentModule = () => {
  const [isProcessing, setIsProcessing] = useState(false);

  const initIAP = async () => {
    try {
      await RNIap.initConnection();
      await RNIap.getProducts(itemSkus);
    } catch (err) {
      console.warn(err);
    }
  };

  const purchaseProduct = async (sku) => {
    if (isProcessing) return;
    setIsProcessing(true);

    const deviceIntegrity = await checkDeviceIntegrity();
    if (!deviceIntegrity) {
      Alert.alert('Security Alert', 'Device integrity check failed.');
      setIsProcessing(false);
      return;
    }

    try {
      const purchase = await RNIap.requestPurchase(sku);
      // Handle successful purchase
      Alert.alert('Purchase Successful', `You bought ${sku}`);
    } catch (err) {
      console.warn(err);
      Alert.alert('Purchase Failed', 'Please try again later.');
    } finally {
      setIsProcessing(false);
    }
  };

  const checkDeviceIntegrity = async () => {
    const isEmulator = await DeviceInfo.isEmulator();
    const isRooted = await DeviceInfo.isRooted();
    return !(isEmulator || isRooted);
  };

  React.useEffect(() => {
    initIAP();
    const purchaseUpdateSubscription = purchaseUpdatedListener((purchase) => {
      // Handle purchase updates
    });

    return () => {
      purchaseUpdateSubscription.remove();
      RNIap.endConnection();
    };
  }, []);

  return (
    <View>
      {itemSkus.map((sku) => (
        <Button key={sku} title={`Buy ${sku}`} onPress={() => purchaseProduct(sku)} />
      ))}
    </View>
  );
};

export default PaymentModule;